mapper.select:
SELECT n.*, u.username AS source_username, u.user_pic AS source_user_avatar
FROM notification n
LEFT JOIN user u ON n.source_user_id = u.id
WHERE n.user_id = #{userId}
ORDER BY n.create_time DESC
LIMIT #{offset}, #{limit}

SELECT n.*, u.username AS source_username, u.user_pic AS source_user_avatar
FROM notification n
LEFT JOIN user u ON n.source_user_id = u.id
WHERE n.user_id = #{userId} AND n.type = #{type}
ORDER BY n.create_time DESC
LIMIT #{offset}, #{limit}

mapper.insert:
INSERT INTO notification_count (user_id, unread_count,
    like_count
    favorite_count
    comment_count
    follow_count
    repost_count
) VALUES (#{userId}, #{delta},
    #{delta}
    #{delta}
    #{delta}
    #{delta}
    #{delta}
)
ON DUPLICATE KEY UPDATE
    unread_count = unread_count + #{delta},
    like_count = like_count + #{delta}
    favorite_count = favorite_count + #{delta}
    comment_count = comment_count + #{delta}
    follow_count = follow_count + #{delta}
    repost_count = repost_count + #{delta}

mapper.delete:
DELETE FROM notification
WHERE user_id = #{userId}
AND id NOT IN (
    SELECT id FROM (
        SELECT id FROM notification WHERE user_id = #{userId}
        ORDER BY create_time DESC LIMIT #{keepCount}
    ) AS temp
)
